SELECT c.*, d.name AS userName FROM ( SELECT a.* FROM sys_log a INNER JOIN ( SELECT a.id FROM sys_log a
LEFT JOIN sys_user e ON a.user_id = e.user_id
WHERE a.is_deleted = 0
AND a.id = #{log.id}
AND a.request_desc LIKE '%' || #{log.requestDesc} || '%'
AND a.response_code = #{log.responseCode}
AND e.name LIKE '%' || #{log.userName} || '%'
AND a.request_ip LIKE '%' || #{log.requestIp} || '%'
AND a.create_time BETWEEN #{log.logsStartDate} AND #{log.logsEndDate}
AND a.log_system = #{log.logSystem}
ORDER BY a.id DESC ) b ON a.id = b.id ) c LEFT JOIN sys_user d ON c.user_id = d.user_id

SELECT
    count(*)
FROM sys_log a

    LEFT JOIN sys_user e ON a.user_id = e.user_id

WHERE
    a.is_deleted = 0

    AND a.id = #{log.id}


    AND a.request_desc LIKE '%' || #{log.requestDesc} || '%'


    AND a.response_code =#{log.responseCode}


    AND e.name LIKE '%' || #{log.userName} || '%'


    AND a.create_time BETWEEN #{log.logsStartDate} AND #{log.logsEndDate}


    AND a.log_system BETWEEN #{log.logSystem} AND #{log.logSystem}

SELECT a.id, a.user_id, a.request_ip, a.request_url, a.request_desc, a.request_params, a.elapsed_time, a.response_code, a.exception_msg, a.create_time, a.update_time, a.is_deleted, b.name AS user_name FROM sys_log a LEFT JOIN sys_user b ON a.user_id=b.user_id WHERE 1=1
AND a.id = #{log.id}
AND b.name LIKE '%' || #{log.userName} || '%'
AND a.request_desc LIKE '%' || #{log.requestDesc} || '%'
AND a.response_code =#{log.responseCode}
AND a.create_time BETWEEN #{log.logsStartDate} AND #{log.logsEndDate}
ORDER BY a.create_time DESC

SELECT
    a.*,
    b.name AS user_name
FROM sys_log a
    LEFT JOIN sys_user b ON a.user_id = b.user_id
WHERE
1=1

    AND a.id = #{log.id}


    AND a.request_url = #{log.requestUrl}


    AND b.inst_id = #{log.instId}


    AND a.response_code = #{log.responseCode}


    AND a.log_system = #{log.logSystem}


    AND a.create_time BETWEEN #{log.logsStartDate} AND #{log.logsEndDate}

    AND a.is_deleted = 0

SELECT l.request_params COUNT(l.request_params) AS num FROM sys_log l WHERE 1=1
AND l.user_id IN
#{userId}
AND l.create_time BETWEEN #{logsStartDate} AND #{logsEndDate}
AND (l.request_desc = '档案检索' OR l.request_desc = '检索查看' )
GROUP BY l.request_params

